export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  // flatten any shape into a single datapoint array
  const points = Array.isArray(inputs?.avgCpuMetrics)
    ? inputs.avgCpuMetrics
    : Array.isArray(inputs?.avgCpuMetrics?.timeseries)
        ? inputs.avgCpuMetrics.timeseries.flatMap(({ data }) => data || [])
        : [];

  if (points.length === 0) return 0;

  // treat missing averages as 0 (idle)
  const values = points.map(({ average }) =>
    typeof average === 'number' ? average : 0
  );

  values.sort((a, b) => a - b);
  const idx = Math.max(0, Math.floor(values.length * 0.95) - 1);
  return values[idx];
};

export const code = async (inputs) => {
  const points =
    Array.isArray(inputs?.memoryMetrics)
      ? inputs.memoryMetrics
      : Array.isArray(inputs?.memoryMetrics?.timeseries)
          ? inputs.memoryMetrics.timeseries.flatMap(({ data }) => data || [])
          : [];

  const usedPercentages = points
    .filter(({ minimum }) => typeof minimum === 'number')
    .map(({ minimum }) => 100 - minimum); // convert to Used Memory %

  if (usedPercentages.length === 0) return 0;

  // Maximum percentage usage
  return Math.max(...usedPercentages);
};

export const code = async (inputs) => {
  const caps = inputs?.sku?.capabilities ?? [];
  const get = (name) => caps.find((c) => c.name === name)?.value;

  return {
    vCPUs: Number(get('vCPUs')),
    PremiumIO: get('PremiumIO') ?? 'False',
    MemoryGB: Number(get('MemoryGB')),
    AcceleratedNetworkingEnabled: get('AcceleratedNetworkingEnabled') ?? 'False',
  };
};

export const code = async (inputs) => {
  const skus = Array.isArray(inputs.skus) ? inputs.skus : [];
  const currentSku = String(inputs.currentSku ?? "");
  const cur = inputs.currentSkuProperties ?? {};
  const minCPU = Number(inputs.minSuggestedCPU ?? 0);
  const minMemGB = Number(inputs.minSuggestedMemoryInGB ?? 0);

  const curCPU = Number(cur.vCPUs ?? cur.vcpus ?? cur.numberOfCores ?? 0);
  const curMemGB = Number(cur.MemoryGB ?? cur.memoryGB ?? 0);

  const parseVmName = (name) => {
    const s = String(name || "");
    const m = s.match(/^Standard_([A-Za-z]+)(\d+)([^_]*)_v(\d+)$/); // e.g. Standard_D4s_v3, Standard_E4-2s_v6
    if (!m) return { prefix: "", family: "", size: NaN, suffix: "", version: NaN };
    return {
      prefix: "Standard_",
      family: m[1],
      size: Number(m[2]),
      suffix: m[3] || "",
      version: Number(m[4]),
    };
  };

  const curParsed = parseVmName(currentSku);
  const currentFamilyToken = curParsed.prefix ? `${curParsed.prefix}${curParsed.family}` : "";

  const memMbToGb = (mb) => (Number(mb) || 0) / 1024;

  // candidates must be strictly smaller than current (downsize)
  const candidatesAll = skus
    .map((s) => ({
      name: String(s.name ?? ""),
      cpu: Number(s.numberOfCores ?? s.vCPUs ?? s.vcpus ?? 0),
      memGB: memMbToGb(s.memoryInMB ?? s.memoryInMb ?? s.memoryMb),
      raw: s,
      parsed: parseVmName(s.name),
    }))
    .filter((c) => c.name && Number.isFinite(c.cpu) && Number.isFinite(c.memGB))
    .filter((c) => c.cpu < curCPU || c.memGB < curMemGB);

  // if already at/below suggested mins, don't suggest anything
  if ((curCPU <= minCPU && curMemGB <= minMemGB) || candidatesAll.length === 0) {
    return { proposedSku: "" };
  }

  const sameFamily = candidatesAll.filter((c) => currentFamilyToken && c.name.startsWith(currentFamilyToken));
  const pool = sameFamily.length ? sameFamily : candidatesAll;

  const score = (c) => {
    const cpuDiff = Math.abs(c.cpu - minCPU);
    const memDiff = Math.abs(c.memGB - minMemGB);

    // penalize under-shooting mins more than overshooting
    const cpuUnder = c.cpu < minCPU ? (minCPU - c.cpu) * 10 : 0;
    const memUnder = c.memGB < minMemGB ? (minMemGB - c.memGB) * 10 : 0;

    // prefer closer but also prefer smaller-than-current (extra tie-breaker)
    const cpuDown = curCPU - c.cpu;
    const memDown = curMemGB - c.memGB;

    // prefer same major version when possible
    const verPenalty =
      Number.isFinite(curParsed.version) && Number.isFinite(c.parsed.version)
        ? Math.abs(curParsed.version - c.parsed.version) * 0.25
        : 0;

    return (
      cpuDiff * 1 +
      memDiff * 1 +
      cpuUnder +
      memUnder +
      verPenalty +
      (cpuDown >= 0 ? cpuDown * 0.05 : 1000) +
      (memDown >= 0 ? memDown * 0.01 : 1000)
    );
  };

  let best = null;
  let bestScore = Infinity;

  for (const c of pool) {
    const sc = score(c);
    if (sc < bestScore) {
      bestScore = sc;
      best = c;
    } else if (sc === bestScore && best) {
      // tie-breakers: same family > higher cpu > higher mem (closer to mins) > lexicographic
      const bestSameFam = currentFamilyToken && best.name.startsWith(currentFamilyToken);
      const cSameFam = currentFamilyToken && c.name.startsWith(currentFamilyToken);
      if (cSameFam && !bestSameFam) best = c;
      else if (cSameFam === bestSameFam) {
        if (c.cpu > best.cpu) best = c;
        else if (c.cpu === best.cpu) {
          if (c.memGB > best.memGB) best = c;
          else if (c.memGB === best.memGB) {
            if (c.name < best.name) best = c;
          }
        }
      }
    }
  }

  return { proposedSku: best?.name ?? "nosku" };
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;
  const currency = prices[0][2];

  return {
    average,
    currency,
  };
};

export const code = async (inputs) => {
  const system = String(inputs.currentVmSystem || "").toLowerCase(); // "windows" | "linux"
  const currentAvgPricePerDay = Number(inputs.currentAvgPrice || 0);

  const pickUnitPrice = (items, system) => {
    const arr = Array.isArray(items) ? items : [];
    const isWindows = system === "windows";

    const isVm = (x) => String(x?.serviceName || "") === "Virtual Machines";
    const isConsumption = (x) => String(x?.type || "") === "Consumption";
    const notSpotOrLowPri = (x) => {
      const n = `${x?.meterName || ""} ${x?.skuName || ""} ${x?.productName || ""}`.toLowerCase();
      return !n.includes("spot") && !n.includes("low priority");
    };
    const osMatch = (x) => {
      const pn = String(x?.productName || "").toLowerCase();
      const hasWindows = pn.includes("windows");
      return isWindows ? hasWindows : !hasWindows;
    };

    const candidates = arr.filter(isVm).filter(isConsumption).filter(notSpotOrLowPri).filter(osMatch);
    if (!candidates.length) return null;

    candidates.sort((a, b) => {
      const aPrim = a?.isPrimaryMeterRegion ? 0 : 1;
      const bPrim = b?.isPrimaryMeterRegion ? 0 : 1;
      if (aPrim !== bPrim) return aPrim - bPrim;

      const aDate = Date.parse(a?.effectiveStartDate || "") || 0;
      const bDate = Date.parse(b?.effectiveStartDate || "") || 0;
      if (aDate !== bDate) return bDate - aDate;

      const aPrice = Number(a?.unitPrice ?? a?.retailPrice ?? Infinity);
      const bPrice = Number(b?.unitPrice ?? b?.retailPrice ?? Infinity);
      return aPrice - bPrice;
    });

    const best = candidates[0];
    const price = Number(best?.unitPrice ?? best?.retailPrice);
    return Number.isFinite(price) ? price : null;
  };

  const currentUnit = pickUnitPrice(inputs.currentSkuPriceList, system);
  const proposedUnit = pickUnitPrice(inputs.proposedSkuPriceList, system);

  if (!Number.isFinite(currentUnit) || !Number.isFinite(proposedUnit) || currentUnit <= 0) {
    return { discount: "0", savings: "0.00" };
  }

  const discountPct = Math.max(0, (1 - proposedUnit / currentUnit) * 100);
  const monthlyCurrent = currentAvgPricePerDay * 30.4;
  const savings = monthlyCurrent * (discountPct / 100);

  return {
    discount: String(Math.round(discountPct)),
    savings: savings.toFixed(2),
  };
};
